const App = require("./app");
const assert = require("assert");

// 1. ROUTE PARAMS (single + multiple)
let app = new App();
app.get("/users/:id", req => ({ status: 200, body: req.params }));
assert.deepStrictEqual(app.handle({ method: "GET", path: "/users/42" }), { status: 200, body: { id: "42" } });

app.get("/a/:x/b/:y", req => ({ status: 200, body: req.params }));
assert.deepStrictEqual(app.handle({ method: "GET", path: "/a/1/b/2" }).body, { x: "1", y: "2" });

// 2. MIDDLEWARE order + next + short-circuit
let order = [];
let app2 = new App();
app2.use((req, next) => { order.push("m1"); return next(); });
app2.use((req, next) => { order.push("m2"); return next(); });
app2.get("/x", req => { order.push("handler"); return { status: 200, body: "ok" }; });
let res2 = app2.handle({ method: "GET", path: "/x" });
assert.deepStrictEqual(order, ["m1", "m2", "handler"]);
assert.deepStrictEqual(res2, { status: 200, body: "ok" });

// short-circuit: middleware returns response without next -> handler not run
let ran = false;
let app3 = new App();
app3.use((req, next) => ({ status: 401, body: "denied" }));
app3.get("/y", req => { ran = true; return { status: 200 }; });
let res3 = app3.handle({ method: "GET", path: "/y" });
assert.deepStrictEqual(res3, { status: 401, body: "denied" });
assert.strictEqual(ran, false);

// 3. METHOD-AWARE 404
let app4 = new App();
app4.get("/z", req => ({ status: 200 }));
assert.deepStrictEqual(app4.handle({ method: "POST", path: "/z" }), { status: 404, body: "Not Found" });
assert.deepStrictEqual(app4.handle({ method: "GET", path: "/nope" }), { status: 404, body: "Not Found" });

// 4. handler return value is the response
let app5 = new App();
app5.post("/p", req => ({ status: 201, body: "created" }));
assert.deepStrictEqual(app5.handle({ method: "POST", path: "/p" }), { status: 201, body: "created" });

console.log("ALL TESTS PASSED");
'

